code = """import json

# Load the min/max price data
trade_summary = locals()['var_functions.query_db:64']

# Calculate total returns for each index
results = []
for rec in trade_summary:
    min_price = float(rec['min_price'])
    max_price = float(rec['max_price'])
    
    if min_price > 0:
        total_return = (max_price - min_price) / min_price
        results.append({
            'Index': rec['Index'],
            'TotalReturn': total_return
        })

# Sort by total return descending
top_5 = sorted(results, key=lambda x: x['TotalReturn'], reverse=True)[:5]

# Map indices to countries
index_to_country = {
    'N225': 'Japan',
    'HSI': 'Hong Kong',
    '000001.SS': 'China',
    '399001.SZ': 'China',
    'IXIC': 'USA',
    'NYA': 'USA',
    'GSPTSE': 'Canada',
    'J203.JO': 'South Africa',
    'NSEI': 'India',
    'GDAXI': 'Germany',
    'N100': 'Netherlands',
    'SSMI': 'Switzerland',
    'TWII': 'Taiwan'
}

# Final output with countries and percentage returns
final_output = []
for r in top_5:
    final_output.append({
        'Index': r['Index'],
        'Country': index_to_country.get(r['Index'], 'Unknown'),
        'TotalReturnPercent': round(r['TotalReturn'] * 100, 2)
    })

print('__RESULT__:')
print(json.dumps(final_output))"""

